import { useState } from "react";

// components
import { Tooltip } from "@mui/material";

// styles
import { Container, Wrapper, Left, LogoContainer, Image, Right, Menu, Icon, Burger, Item } from "./navbar.styles";

// translate
import translate from '../../translate/fr.json'

const Navbar = () => {
  const [open, setOpen] = useState(false);
  const toggleOpen = () => setOpen((value) => !value);
  return (
    <Container>
      <Wrapper>
        <Left>
          <LogoContainer>
            <Tooltip title={translate.tooltip.returnHome} placement="bottom">
              <Image alt="Seoul Lab" src="img/LogoYellow.png" />
            </Tooltip>
          </LogoContainer>
        </Left>
        <Right>
          <Menu open={open}>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.home}></Item>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.menu}></Item>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.map}></Item>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.instagram}></Item>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.contact}></Item>
            <Item onClick={toggleOpen} data-link={translate.navigation.navbar.login}></Item>
          </Menu>
          <Icon onClick={() => setOpen(!open)}>
            <Burger open={open}></Burger>
            <Burger open={open}></Burger>
            <Burger open={open}></Burger>
          </Icon>
        </Right>
      </Wrapper>
    </Container>
  );
};

export default Navbar;