import { Size, Colors } from "../common/variables";

// types
interface open {
  readonly open: boolean;
}

export const Container = styled('header')`
  display: flex;
  justify-content: center;
  position: fixed;
  width: 100%;
  z-index: 99;
  /* unique: Glassmorphism */
  background: rgba( 255, 255, 255, 0.2 );
  backdrop-filter: blur( 9px );
  -webkit-backdrop-filter: blur( 9px );
`;
export const Wrapper = styled('div')`
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: ${Size.width};
  height: ${Size.heightNavigationNavbar};
`;
export const Left = styled('div')`
  flex: 1;
  display: flex;
  justify-content: left;
  align-items: center;
`;
export const LogoContainer = styled('article')`
  display: flex;
  align-items: center;
  width: 180px;
  height: 100%;
  cursor: pointer;
`;
export const Image = styled('img')`
  width: 45px;
  height: 45px;
`;
export const Right = styled('div')`
  flex: 1;
  display: flex;
  justify-content: right;
  align-items: center;
`;
export const Menu = styled('div')<open>`
  font-family: "Zilla Slab", sans-serif;
  list-style: none;
  background: ${Colors.background.navbar};
  display: flex;
  align-items: center;
  justify-content: center;
  margin-left: 20px;
  flex-flow: column nowrap;
  position: fixed;
  right: ${(props) => (props.open ? "0px" : "-100%")};
  top: 0;
  height: 100vh;
  width: 100%;
  z-index: 99;
  transition: all 0.3s linear;
`;
export const Item = styled('a')`
  margin-bottom: 2rem;
  width: 100%;
  height: ${Size.heightNavigationNavbar};
  line-height: 55px;
  text-align: center;
  position: relative;
  overflow: hidden;
  cursor: pointer;
  font-size: 3vh;
  &:before,
  &:after {
    position: absolute;
    content: attr(data-link);
    width: 100%;
    transition: all 0.75s;
  }
  &:before {
    top: 0;
    left: 0;
  }
  &:after {
    top: 100%;
    left: 0;
    color: ${Colors.text.navbar};
  }
  &:hover:before {
    @media (hover: hover) {
      top: -100%;
    }
  }
  &:hover:after {
    @media (hover: hover) {
      top: 0;
    }
  }
`;
export const Icon = styled('div')`
  width: 30px;
  height: 20px;
  z-index: 99;
  display: none;
  cursor: pointer;
  position: relative;
  font-family: "Zilla Slab", sans-serif;
  position: fixed;
  display: flex;
`;
export const Burger = styled('div')<open>`
  width: 30px;
  height: 3px;
  background: ${Colors.common.white};
  border-radius: 10px;
  transition: all 0.3s linear;
  cursor: pointer;
  position: absolute;
  &:nth-child(1) {
    top: ${(props) => (props.open ? "50%" : "0")};
    transform: ${(props) => (props.open ? "rotate(45deg)" : "rotate(0)")};
  }
  &:nth-child(2) {
    top: 50%;
    transform: ${(props) =>
      props.open ? "translateX(100%)" : "translateX(0)"};
    opacity: ${(props) => (props.open ? 0 : 1)};
  }
  &:nth-child(3) {
    top: ${(props) => (props.open ? "50%" : "100%")};
    transform: ${(props) => (props.open ? "rotate(-45deg)" : "rotate(0)")};
  }
`;

